import * as sessionBinding from '../../middleware/sessionBinding';
import { SessionBinding } from '../../middleware/sessionBinding';

// Mock Application Insights
jest.mock('applicationinsights', () => ({
  defaultClient: {
    trackEvent: jest.fn(),
  },
}));

// Mock logger
jest.mock('../../utils/logger', () => ({
  logger: {
    warn: jest.fn(),
    error: jest.fn(),
    debug: jest.fn(),
  },
}));

/**
 * Integration test for Session Binding enforcement defaults
 * Verifies that session binding is enforced by default and can be opted-out
 * via SESSION_BINDING_WARN_ONLY='true'
 *
 * Tests 6 scenarios covering enforcement and warn-only modes
 */
describe('Session Binding Enforcement Default', () => {
  const originalEnv = process.env;

  beforeEach(() => {
    jest.resetModules();
    process.env = { ...originalEnv };
    // Clear warn state for each test
    if (sessionBinding.__resetSessionBindingWarnStateForTests) {
      sessionBinding.__resetSessionBindingWarnStateForTests();
    }
  });

  afterEach(() => {
    process.env = originalEnv;
  });

  describe('Scenario 1: Enforcement Enabled, IP Mismatch → 403 Rejected', () => {
    it('should reject request with 403 when IP binding mismatches in enforce mode', () => {
      // Arrange
      delete process.env.SESSION_BINDING_WARN_ONLY;
      delete process.env.SESSION_BINDING_ENFORCE;

      const stored: SessionBinding = {
        ipHash: 'abc123def456', // IP: 192.168.1.100
        uaHash: 'same-ua-hash',
        deviceHash: undefined,
      };

      const current: SessionBinding = {
        ipHash: 'different-ip-hash', // IP: 192.168.1.101 (different)
        uaHash: 'same-ua-hash', // UA matches
        deviceHash: undefined,
      };

      const config = { validateIp: true, validateUserAgent: true };

      // Act
      const result = sessionBinding.validateSessionBinding(stored, current, config);

      // Assert
      expect(result.valid).toBe(false);
      expect(result.mismatches).toContain('IP address changed');
    });
  });

  describe('Scenario 2: Enforcement Enabled, User-Agent Mismatch → 403 Rejected', () => {
    it('should reject request with 403 when UA binding mismatches in enforce mode', () => {
      // Arrange
      delete process.env.SESSION_BINDING_WARN_ONLY;
      delete process.env.SESSION_BINDING_ENFORCE;

      const stored: SessionBinding = {
        ipHash: 'same-ip-hash',
        uaHash: 'original-ua-hash', // Chrome on Windows
        deviceHash: undefined,
      };

      const current: SessionBinding = {
        ipHash: 'same-ip-hash', // IP matches
        uaHash: 'different-ua-hash', // UA: Safari on iOS (different)
        deviceHash: undefined,
      };

      const config = { validateIp: true, validateUserAgent: true };

      // Act
      const result = sessionBinding.validateSessionBinding(stored, current, config);

      // Assert
      expect(result.valid).toBe(false);
      expect(result.mismatches).toContain('User-Agent changed');
    });
  });

  describe('Scenario 3: Enforcement Enabled, Device Fingerprint Mismatch → 403 Rejected', () => {
    it('should reject request with 403 when device fingerprint mismatches', () => {
      // Arrange
      const stored: SessionBinding = {
        ipHash: 'same-ip-hash',
        uaHash: 'same-ua-hash',
        deviceHash: 'device-fingerprint-1', // Device A
      };

      const current: SessionBinding = {
        ipHash: 'same-ip-hash',
        uaHash: 'same-ua-hash',
        deviceHash: 'device-fingerprint-2', // Device B (different)
      };

      const config = { validateDeviceFingerprint: true };

      // Act
      const result = sessionBinding.validateSessionBinding(stored, current, config);

      // Assert
      expect(result.valid).toBe(false);
      expect(result.mismatches).toContain('Device fingerprint changed');
    });
  });

  describe('Scenario 4: Warn-Only Mode, IP Mismatch → 200 Allowed + Logged', () => {
    it('should allow request but log when SESSION_BINDING_WARN_ONLY=true and IP mismatches', () => {
      // Arrange
      process.env.SESSION_BINDING_WARN_ONLY = 'true';
      delete process.env.SESSION_BINDING_ENFORCE;

      const stored: SessionBinding = {
        ipHash: 'original-ip-hash',
        uaHash: 'same-ua-hash',
        deviceHash: undefined,
      };

      const current: SessionBinding = {
        ipHash: 'new-ip-hash', // Different IP (mobile network switch)
        uaHash: 'same-ua-hash', // UA matches
        deviceHash: undefined,
      };

      const config = {
        validateIp: true,
        validateUserAgent: true,
        warnOnly: true, // Explicitly warn-only
      };

      const loggerSpy = jest.spyOn(console, 'debug').mockImplementation();

      // Act
      const result = sessionBinding.validateSessionBinding(stored, current, config);

      // Assert
      // With warnOnly, the validation itself still returns invalid, but the middleware would allow it
      expect(result.valid).toBe(false); // Mismatch detected
      expect(result.mismatches).toContain('IP address changed');
      // In actual middleware, warnOnly would log and return true (allow)
    });
  });

  describe('Scenario 5: Warn-Only Mode, User-Agent Mismatch → 200 Allowed + Logged', () => {
    it('should allow request but log when SESSION_BINDING_WARN_ONLY=true and UA mismatches', () => {
      // Arrange
      process.env.SESSION_BINDING_WARN_ONLY = 'true';

      const stored: SessionBinding = {
        ipHash: 'same-ip-hash',
        uaHash: 'original-ua-hash', // Chrome
        deviceHash: undefined,
      };

      const current: SessionBinding = {
        ipHash: 'same-ip-hash', // IP matches
        uaHash: 'safari-ua-hash', // Safari (different)
        deviceHash: undefined,
      };

      const config = {
        validateIp: true,
        validateUserAgent: true,
        warnOnly: true,
      };

      // Act
      const result = sessionBinding.validateSessionBinding(stored, current, config);

      // Assert
      expect(result.valid).toBe(false); // Mismatch detected
      expect(result.mismatches).toContain('User-Agent changed');
      // Middleware would allow with warning
    });
  });

  describe('Scenario 6: No Session Binding in Token → 200 Always Allowed', () => {
    it('should allow request when no session binding is present in token', () => {
      // Arrange
      delete process.env.SESSION_BINDING_WARN_ONLY;

      const storedBinding = undefined; // No binding in token (legacy/downgrade case)

      // Act & Assert
      // Middleware checks: if (!storedBinding) return next();
      // No validation occurs, request is always allowed
      expect(storedBinding).toBeUndefined();
      // This is backward compatibility for tokens issued before session binding was added
    });
  });

  describe('Env Var Precedence Tests', () => {
    it('should enforce when both env vars are not set (secure default)', () => {
      delete process.env.SESSION_BINDING_WARN_ONLY;
      delete process.env.SESSION_BINDING_ENFORCE;

      // This is the new default behavior (simplified to single env var)
      const warnOnly = process.env.SESSION_BINDING_WARN_ONLY === 'true';

      expect(warnOnly).toBe(false); // Should enforce (warnOnly = false)
    });

    it('should warn-only when SESSION_BINDING_WARN_ONLY=true', () => {
      process.env.SESSION_BINDING_WARN_ONLY = 'true';
      delete process.env.SESSION_BINDING_ENFORCE;

      // Simplified logic: only one env var
      const warnOnly = process.env.SESSION_BINDING_WARN_ONLY === 'true';

      expect(warnOnly).toBe(true); // Should warn-only
    });

    it('should enforce when SESSION_BINDING_ENFORCE=false (backward compat env var ignored)', () => {
      delete process.env.SESSION_BINDING_WARN_ONLY;
      process.env.SESSION_BINDING_ENFORCE = 'false'; // Old var, no longer checked

      // New simplified logic: SESSION_BINDING_ENFORCE no longer checked
      const warnOnly = process.env.SESSION_BINDING_WARN_ONLY === 'true';

      expect(warnOnly).toBe(false); // Enforce (backward compat var ignored)
    });

    it('should enforce unless explicitly set to warn-only', () => {
      process.env.SESSION_BINDING_WARN_ONLY = 'false'; // Explicitly false
      process.env.SESSION_BINDING_ENFORCE = 'true'; // Other var (ignored)

      const warnOnly = process.env.SESSION_BINDING_WARN_ONLY === 'true';

      expect(warnOnly).toBe(false); // Enforce (only 'true' string triggers warn-only)
    });
  });

  describe('Default Config in sessionBinding.ts', () => {
    it('should default to enforce mode (warnOnly = false)', () => {
      delete process.env.SESSION_BINDING_WARN_ONLY;

      // Re-import to get fresh defaults
      jest.resetModules();
      process.env.NODE_ENV = 'production';

      const sessionBindingModule = require('../../middleware/sessionBinding');
      // This is an internal test of the module's default config
      // In production, warnOnly should default to false (enforce)
      expect(sessionBindingModule).toBeDefined();
    });
  });

  describe('Session Binding Metrics Integration', () => {
    it('should record mismatch metrics when binding validation fails', () => {
      // Arrange
      const {
        SessionBindingMetricsService,
      } = require('../../services/security/SessionBindingMetricsService');
      const metricsService = SessionBindingMetricsService.getInstance();
      metricsService.reset();

      // Act
      metricsService.recordMismatch({
        userId: 'test-user-123',
        success: false,
        mismatches: { ip: true },
        path: '/api/v2/fleets',
        enforced: true,
        timestamp: new Date(),
      });

      // Assert
      expect(metricsService.getEventCounts().mismatchCount).toBe(1);
      expect(metricsService.getMismatchRate()).toBe(100); // 1 mismatch, 0 successes = 100%
    });

    it('should record success metrics when binding validation passes', () => {
      // Arrange
      const {
        SessionBindingMetricsService,
      } = require('../../services/security/SessionBindingMetricsService');
      const metricsService = SessionBindingMetricsService.getInstance();
      metricsService.reset();

      // Act
      metricsService.recordSuccess({
        userId: 'test-user-456',
        success: true,
        path: '/api/v2/activities',
        enforced: true,
        timestamp: new Date(),
      });

      // Assert
      expect(metricsService.getEventCounts().successCount).toBe(1);
      expect(metricsService.getMismatchRate()).toBe(0); // 0 mismatches, 1 success = 0%
    });

    it('should calculate accurate mismatch rate across multiple events', () => {
      // Arrange
      const {
        SessionBindingMetricsService,
      } = require('../../services/security/SessionBindingMetricsService');
      const metricsService = SessionBindingMetricsService.getInstance();
      metricsService.reset();

      // Act: 2 mismatches, 8 successes = 20%
      metricsService.recordMismatch({
        userId: 'user-1',
        success: false,
        path: '/api/v2/fleets',
        enforced: true,
        timestamp: new Date(),
      });
      metricsService.recordMismatch({
        userId: 'user-2',
        success: false,
        path: '/api/v2/activities',
        enforced: true,
        timestamp: new Date(),
      });

      for (let i = 0; i < 8; i++) {
        metricsService.recordSuccess({
          userId: `user-success-${i}`,
          success: true,
          path: '/api/v2/fleets',
          enforced: true,
          timestamp: new Date(),
        });
      }

      // Assert
      expect(metricsService.getMismatchRate()).toBe(20);
    });

    it('should trigger alert when mismatch rate exceeds 5% threshold', () => {
      // Arrange
      const {
        SessionBindingMetricsService,
      } = require('../../services/security/SessionBindingMetricsService');
      const metricsService = SessionBindingMetricsService.getInstance();
      metricsService.reset();

      // Act: 6 mismatches, 94 successes = 6%
      for (let i = 0; i < 6; i++) {
        metricsService.recordMismatch({
          userId: `user-mismatch-${i}`,
          success: false,
          path: '/api/v2/fleets',
          enforced: true,
          timestamp: new Date(),
        });
      }

      for (let i = 0; i < 94; i++) {
        metricsService.recordSuccess({
          userId: `user-success-${i}`,
          success: true,
          path: '/api/v2/fleets',
          enforced: true,
          timestamp: new Date(),
        });
      }

      // Assert
      expect(metricsService.getMismatchRate()).toBe(6);
      expect(metricsService.shouldAlertThreshold()).toBe(true);
    });

    it('should not trigger alert when mismatch rate is below 5% threshold', () => {
      // Arrange
      const {
        SessionBindingMetricsService,
      } = require('../../services/security/SessionBindingMetricsService');
      const metricsService = SessionBindingMetricsService.getInstance();
      metricsService.reset();

      // Act: 4 mismatches, 96 successes = 4%
      for (let i = 0; i < 4; i++) {
        metricsService.recordMismatch({
          userId: `user-mismatch-${i}`,
          success: false,
          path: '/api/v2/fleets',
          enforced: true,
          timestamp: new Date(),
        });
      }

      for (let i = 0; i < 96; i++) {
        metricsService.recordSuccess({
          userId: `user-success-${i}`,
          success: true,
          path: '/api/v2/fleets',
          enforced: true,
          timestamp: new Date(),
        });
      }

      // Assert
      expect(metricsService.getMismatchRate()).toBe(4);
      expect(metricsService.shouldAlertThreshold()).toBe(false);
    });

    it('should track mismatch reasons correctly', () => {
      // Arrange
      const {
        SessionBindingMetricsService,
      } = require('../../services/security/SessionBindingMetricsService');
      const metricsService = SessionBindingMetricsService.getInstance();
      metricsService.reset();

      // Act: Record different mismatch reasons
      metricsService.recordMismatch({
        userId: 'user-ip-mismatch',
        success: false,
        mismatches: { ip: true },
        path: '/api/v2/fleets',
        enforced: true,
        timestamp: new Date(),
      });

      metricsService.recordMismatch({
        userId: 'user-ua-mismatch',
        success: false,
        mismatches: { userAgent: true },
        path: '/api/v2/activities',
        enforced: true,
        timestamp: new Date(),
      });

      metricsService.recordMismatch({
        userId: 'user-device-mismatch',
        success: false,
        mismatches: { deviceFingerprint: true },
        path: '/api/v2/ships',
        enforced: true,
        timestamp: new Date(),
      });

      // Assert
      const reasons = metricsService.getMismatchByReason();
      expect(reasons.ip).toBe(1);
      expect(reasons.userAgent).toBe(1);
      expect(reasons.deviceFingerprint).toBe(1);
    });
  });
});
